import{_ as t,c as a,o,af as p}from"./chunks/framework.BaM0Nbdx.js";const m=JSON.parse('{"title":"鶯歌老街尋寶記：體驗陶瓷藝術與美食之旅","description":"這次聖小熊要帶大家來到充滿藝術氣息的新北市鶯歌區，一起逛逛熱鬧的鶯歌老街，感受陶瓷文化的魅力，並品嚐在地特色美食！","frontmatter":{"author":"聖小熊","git_date":"2025-05-25T17:01:35.000Z","title":"鶯歌老街尋寶記：體驗陶瓷藝術與美食之旅","date":"2025-05-23T00:00:00.000Z","description":"這次聖小熊要帶大家來到充滿藝術氣息的新北市鶯歌區，一起逛逛熱鬧的鶯歌老街，感受陶瓷文化的魅力，並品嚐在地特色美食！","image":"https://shoplineimg.com/5e82ba489e08ce0053908f85/67a5b0e10ea626000dc6d800/800x.webp","tag":["鶯歌","老街","陶瓷","美食","台灣旅遊"],"category":["旅遊"]},"headers":[],"relativePath":"blog/2025-05-23.md","filePath":"blog/2025-05-23.md"}'),s={name:"blog/2025-05-23.md"};function r(c,e,l,n,i,_){return o(),a("div",null,e[0]||(e[0]=[p('<p>嗨，大家好！這次聖小熊要帶大家來到充滿藝術氣息的新北市鶯歌區，一起逛逛熱鬧的鶯歌老街，感受陶瓷文化的魅力，並品嚐在地特色美食！</p><p>鶯歌，這個以陶瓷聞名的小鎮，擁有悠久的製陶歷史。一踏進老街，兩旁琳瑯滿目的陶瓷藝品店立刻吸引了我的目光。從精緻的茶具、古樸的花瓶，到可愛的裝飾品，每一件都散發著獨特的藝術光彩，讓人愛不釋手。</p><p><img src="https://shoplineimg.com/5e82ba489e08ce0053908f85/67a5b0e10ea626000dc6d800/800x.webp" alt="鶯歌老街的陶瓷藝品"><small style="display:block;text-align:center;color:#777;">老街上各式各樣的精美陶瓷藝品，令人目不暇給。</small></p><p>走在老街的紅磚道上，不時可以看到師傅們在工作室裡專注地製作陶瓷。那份對傳統工藝的堅持與熱愛，令人由衷敬佩。許多店家也提供 DIY 陶瓷體驗，讓遊客可以親手製作獨一無二的紀念品，非常適合親子同樂。</p><p>除了陶瓷，鶯歌的美食也是不容錯過的。老街上有許多傳統小吃和特色餐廳。我品嚐了香Q彈牙的<strong>阿婆壽司</strong>，還有濃郁入味的<strong>古早味肉羹</strong>，每一口都充滿了在地風味，讓人回味無窮。</p><p>這次的鶯歌老街尋寶之旅，不僅讓我欣賞到精美的陶瓷藝術，也品嚐到了道地的台灣味。如果你也想體驗一趟充滿文化與美食的旅程，不妨找個時間來鶯歌走走吧！</p>',6)]))}const g=t(s,[["render",r]]);export{m as __pageData,g as default};
